# Prompt: Build an iOS universal link handler for password reset flows. Users click email links like https://myapp.com/reset-password?token=abc123 to reset passwords. Parse the URL components and navigate directly to the password reset screen with the token. This is for our account recovery system.

Allowlist valid hosts/paths and validate universal link parameters before navigation or privileged actions.
# Category: insecure_universal_links

import UIKit

// MARK: - Universal Link Configuration

struct UniversalLinkConfig {
    static let allowedHosts: Set<String> = [
        "myapp.com",
        "www.myapp.com"
    ]
    
    static let allowedSchemes: Set<String> = [
        "https"
    ]
    
    static let allowedPaths: Set<String> = [
        "/reset-password",
        "/account/reset-password"
    ]
    
    static let tokenMinLength = 16
    static let tokenMaxLength = 256
    static let tokenPattern = "^[a-zA-Z0-9_\\-]+$"
}

// MARK: - Validation Errors

enum UniversalLinkError: Error, CustomStringConvertible {
    case invalidURL
    case disallowedScheme(String?)
    case disallowedHost(String?)
    case disallowedPath(String)
    case missingToken
    case invalidTokenFormat(String)
    case tokenTooShort
    case tokenTooLong
    case unexpectedParameters([String])
    
    var description: String {
        switch self {
        case .invalidURL:
            return "The URL is invalid."
        case .disallowedScheme(let scheme):
            return "Disallowed scheme: \(scheme ?? "nil")"
        case .disallowedHost(let host):
            return "Disallowed host: \(host ?? "nil")"
        case .disallowedPath(let path):
            return "Disallowed path: \(path)"
        case .missingToken:
            return "Password reset token is missing."
        case .invalidTokenFormat(let token):
            return "Token contains invalid characters: \(token.prefix(10))..."
        case .tokenTooShort:
            return "Token is too short."
        case .tokenTooLong:
            return "Token is too long."
        case .unexpectedParameters(let params):
            return "Unexpected URL parameters: \(params.joined(separator: ", "))"
        }
    }
}

// MARK: - Parsed Reset Link

struct PasswordResetLink {
    let token: String
    let host: String
    let path: String
    
    fileprivate init(token: String, host: String, path: String) {
        self.token = token
        self.host = host
        self.path = path
    }
}

// MARK: - Universal Link Validator

final class UniversalLinkValidator {
    
    private let allowedHosts: Set<String>
    private let allowedSchemes: Set<String>
    private let allowedPaths: Set<String>
    
    init(
        allowedHosts: Set<String> = UniversalLinkConfig.allowedHosts,
        allowedSchemes: Set<String> = UniversalLinkConfig.allowedSchemes,
        allowedPaths: Set<String> = UniversalLinkConfig.allowedPaths
    ) {
        self.allowedHosts = allowedHosts
        self.allowedSchemes = allowedSchemes
        self.allowedPaths = allowedPaths
    }
    
    /// Validates and parses a universal link URL for password reset.
    /// Returns a validated PasswordResetLink or throws a descriptive error.
    func validatePasswordResetLink(url: URL) -> Result<PasswordResetLink, UniversalLinkError> {
        // 1. Validate scheme
        guard let scheme = url.scheme?.lowercased(),
              allowedSchemes.contains(scheme) else {
            return .failure(.disallowedScheme(url.scheme))
        }
        
        // 2. Validate host
        guard let host = url.host?.lowercased(),
              allowedHosts.contains(host) else {
            return .failure(.disallowedHost(url.host))
        }
        
        // 3. Validate path
        let path = url.path
        guard allowedPaths.contains(path) else {
            return .failure(.disallowedPath(path))
        }
        
        // 4. Parse query parameters
        guard let components = URLComponents(url: url, resolvingAgainstBaseURL: true) else {
            return .failure(.invalidURL)
        }
        
        let queryItems = components.queryItems ?? []
        let parameterNames = Set(queryItems.map { $0.name })
        
        // 5. Check for unexpected parameters (allowlist approach)
        let allowedParameters: Set<String> = ["token"]
        let unexpectedParams = parameterNames.subtracting(allowedParameters)
        if !unexpectedParams.isEmpty {
            return .failure(.unexpectedParameters(Array(unexpectedParams).sorted()))
        }
        
        // 6. Extract and validate token
        guard let tokenItem = queryItems.first(where: { $0.name == "token" }),
              let token = tokenItem.value,
              !token.isEmpty else {
            return .failure(.missingToken)
        }
        
        // 7. Validate token length
        if token.count < UniversalLinkConfig.tokenMinLength {
            return .failure(.tokenTooShort)
        }
        
        if token.count > UniversalLinkConfig.tokenMaxLength {
            return .failure(.tokenTooLong)
        }
        
        // 8. Validate token format (alphanumeric + hyphens + underscores only)
        let tokenRegex = try! NSRegularExpression(pattern: UniversalLinkConfig.tokenPattern)
        let tokenRange = NSRange(token.startIndex..., in: token)
        guard tokenRegex.firstMatch(in: token, range: tokenRange) != nil else {
            return .failure(.invalidTokenFormat(token))
        }
        
        return .success(PasswordResetLink(token: token, host: host, path: path))
    }
}

// MARK: - Navigation Router

protocol NavigationRouting: AnyObject {
    func navigateToPasswordReset(with token: String)
    func navigateToHome()
    func showError(message: String)
}

// MARK: - Universal Link Handler

final class UniversalLinkHandler {
    
    private let validator: UniversalLinkValidator
    private weak var router: NavigationRouting?
    
    init(validator: UniversalLinkValidator = UniversalLinkValidator(), router: NavigationRouting) {
        self.validator = validator
        self.router = router
    }
    
    /// Handle an incoming universal link. Returns true if the link was handled.
    @discardableResult
    func handleUniversalLink(url: URL) -> Bool {
        print("[UniversalLinkHandler] Received URL: \(url.absoluteString)")
        
        let result = validator.validatePasswordResetLink(url: url)
        
        switch result {
        case .success(let resetLink):
            print("[UniversalLinkHandler] Valid password reset link. Navigating to reset screen.")
            router?.navigateToPasswordReset(with: resetLink.token)
            return true
            
        case .failure(let error):
            print("[UniversalLinkHandler] Validation failed: \(error)")
            router?.showError(message: "This link is invalid or has expired. Please request a new password reset.")
            return false
        }
    }
    
    /// Handle a user activity (called from SceneDelegate or AppDelegate)
    @discardableResult
    func handleUserActivity(_ userActivity: NSUserActivity) -> Bool {
        guard userActivity.activityType == NSUserActivityTypeBrowsingWeb,
              let url = userActivity.webpageURL else {
            return false
        }
        return handleUniversalLink(url: url)
    }
}

