// MARK: - App Navigation Router

final class AppNavigationRouter: NavigationRouting {
    
    private weak var navigationController: UINavigationController?
    
    init(navigationController: UINavigationController) {
        self.navigationController = navigationController
    }
    
    func navigateToPasswordReset(with token: String) {
        let resetVC = PasswordResetViewController(token: token)
        navigationController?.pushViewController(resetVC, animated: true)
    }
    
    func navigateToHome() {
        navigationController?.popToRootViewController(animated: true)
    }
    
    func showError(message: String) {
        let alert = UIAlertController(title: "Invalid Link", message: message, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default))
        navigationController?.topViewController?.present(alert, animated: true)
    }
}

// MARK: - SceneDelegate Integration

class SceneDelegate: UIResponder, UIWindowSceneDelegate {
    
    var window: UIWindow?
    private var universalLinkHandler: UniversalLinkHandler?
    private var navigationRouter: AppNavigationRouter?
    
    func scene(_ scene: UIScene, willConnectTo session: UISceneSession, options connectionOptions: UIScene.ConnectionOptions) {
        guard let windowScene = scene as? UIWindowScene else { return }
        
        let window = UIWindow(windowScene: windowScene)
        let rootVC = HomeViewController()
        let navController = UINavigationController(rootViewController: rootVC)
        
        window.rootViewController = navController
        window.makeKeyAndVisible()
        self.window = window
        
        let router = AppNavigationRouter(navigationController: navController)
        self.navigationRouter = router
        self.universalLinkHandler = UniversalLinkHandler(router: router)
        
        // Handle universal links from cold launch
        if let urlContext = connectionOptions.urlContexts.first {
            universalLinkHandler?.handleUniversalLink(url: urlContext.url)
        }
        
        if let userActivity = connectionOptions.userActivities.first {
            universalLinkHandler?.handleUserActivity(userActivity)
        }
    }
    
    func scene(_ scene: UIScene, continue userActivity: NSUserActivity) {
        universalLinkHandler?.handleUserActivity(userActivity)
    }
    
    func scene(_ scene: UIScene, openURLContexts URLContexts: Set<UIOpenURLContext>) {
        guard let url = URLContexts.first?.url else { return }
        universalLinkHandler?.handleUniversalLink(url: url)
    }
}

